 1	import React from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import MigrationPolicyModel from '@kubevirt-ui/kubevirt-api/console/models/MigrationPolicyModel';
 5	import { V1alpha1MigrationPolicy } from '@kubevirt-ui/kubevirt-api/kubevirt';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { k8sCreate } from '@openshift-console/dynamic-plugin-sdk';
 8	import {
 9	  ActionList,
10	  ActionListItem,
11	  Alert,
12	  AlertVariant,
13	  Button,
14	  ButtonVariant,
15	  Stack,
16	  StackItem,
17	} from '@patternfly/react-core';
18	
19	import { migrationPoliciesPageBaseURL } from '../../../../utils/constants';
20	
21	type MigrationPolicyFormFooterProps = {
22	  migrationPolicy: V1alpha1MigrationPolicy;
23	};
24	
25	const MigrationPolicyFormFooter: React.FC<MigrationPolicyFormFooterProps> = ({
26	  migrationPolicy,
27	}) => {
28	  const { t } = useKubevirtTranslation();
29	  const navigate = useNavigate();
30	
31	  const [isSubmitting, setIsSubmitting] = React.useState(false);
32	  const [error, setError] = React.useState(undefined);
33	  const migrationPolicyName = migrationPolicy?.metadata?.name;
34	
35	  const handleSubmit: React.MouseEventHandler<HTMLButtonElement> = (e) => {
36	    e.preventDefault();
37	    setIsSubmitting(true);
38	    setError(undefined);
39	
40	    k8sCreate({ data: migrationPolicy, model: MigrationPolicyModel })
41	      .then(() => navigate(`${migrationPoliciesPageBaseURL}/${migrationPolicyName}`))
42	      .catch(setError)
43	      .finally(() => setIsSubmitting(false));
44	  };
45	
46	  const closeModal = () => {
47	    setError(undefined);
48	    setIsSubmitting(false);
49	    navigate(-1);
50	  };
51	
52	  return (
53	    <Stack className="kv-tabmodal-footer" hasGutter>
54	      {error && (
55	        <StackItem>
56	          <Alert isInline title={t('An error occurred')} variant={AlertVariant.danger}>
57	            <Stack hasGutter>
58	              <StackItem>{error?.message}</StackItem>
59	              {error?.href && (
60	                <StackItem>
61	                  <a href={error.href} rel="noreferrer" target="_blank">
62	                    {error.href}
63	                  </a>
64	                </StackItem>
65	              )}
66	            </Stack>
67	          </Alert>
68	        </StackItem>
69	      )}
70	      <StackItem>
71	        <ActionList>
72	          <ActionListItem>
73	            <Button
74	              isDisabled={isSubmitting}
75	              isLoading={isSubmitting}
76	              onClick={handleSubmit}
77	              variant={ButtonVariant.primary}
78	            >
79	              {t('Create')}
80	            </Button>
81	          </ActionListItem>
82	          <ActionListItem>
83	            <Button onClick={closeModal} variant={ButtonVariant.link}>
84	              {t('Cancel')}
85	            </Button>
86	          </ActionListItem>
87	        </ActionList>
88	      </StackItem>
89	    </Stack>
90	  );
91	};
92	
93	export default MigrationPolicyFormFooter;

